// Generated by OrchestKit Claude Plugin
// Created: 2026-07-17

// Static synonym map for docs search. Terms within a group are treated as
// equivalent for RECALL (synonym hits score lower than literal hits — see
// lib/search-relevance.ts). Kept deliberately small: every group must map to
// vocabulary that actually appears in the docs content, otherwise it only
// adds noise to the Orama term set.

/** Bidirectional synonym groups. Single-word, lowercase tokens only. */
const SYNONYM_GROUPS: readonly (readonly string[])[] = [
	["agent", "subagent"],
	["hook", "event"],
	["command", "cmd", "slash-command"],
	["mcp", "server"],
	["playground", "lab"],
	// Extended from content:
	["composition", "pipeline"],
	["write", "create", "author"],
	["install", "setup"],
	["docs", "documentation"],
];

/** token -> other tokens in its group. Multi-part tokens ("slash-command") are
 * also indexed by their parts so tokenized queries still expand. */
const SYNONYM_LOOKUP: ReadonlyMap<string, readonly string[]> = (() => {
	const map = new Map<string, string[]>();
	for (const group of SYNONYM_GROUPS) {
		for (const term of group) {
			const others = group.filter((t) => t !== term);
			const keys = new Set([term, ...term.split("-")]);
			for (const key of keys) {
				const existing = map.get(key) ?? [];
				map.set(key, [...new Set([...existing, ...others])]);
			}
		}
	}
	return map;
})();

const STOPWORDS = new Set([
	"a", "an", "and", "are", "can", "do", "does", "for", "how", "i", "in",
	"is", "it", "my", "of", "on", "or", "the", "to", "what", "when", "with",
]);

/** Lowercase content tokens of a query, stopwords removed. */
export function tokenize(query: string): string[] {
	return query
		.toLowerCase()
		.split(/[^a-z0-9-]+/)
		.map((t) => t.replace(/^-+|-+$/g, ""))
		.filter((t) => t.length > 1 && !STOPWORDS.has(t));
}

export type ExpandedQuery = {
	/** Literal query tokens (stopwords removed). */
	original: string[];
	/** Synonym tokens NOT already present in the original set. */
	synonyms: string[];
};

/** Expand a query with synonyms. Synonyms never duplicate original tokens. */
export function expandQuery(query: string): ExpandedQuery {
	const original = tokenize(query);
	const seen = new Set(original);
	const synonyms: string[] = [];
	for (const term of original) {
		for (const syn of SYNONYM_LOOKUP.get(term) ?? []) {
			// A multi-part synonym ("slash-command") expands to its parts too,
			// since both the docs index and Orama tokenize on hyphens.
			for (const part of new Set([syn, ...syn.split("-")])) {
				if (part.length > 1 && !seen.has(part)) {
					seen.add(part);
					synonyms.push(part);
				}
			}
		}
	}
	return { original, synonyms };
}

/** Query string with synonyms appended — for the Orama full-text path. */
export function expandQueryString(query: string): string {
	const { synonyms } = expandQuery(query);
	if (synonyms.length === 0) return query;
	return `${query} ${synonyms.join(" ")}`;
}
